def p(g):
    nz = [v for r in g for v in r if v]
    lc = max(set(nz), key=nz.count)
    for row in g:
        if 0 in row:
            cols = [c for c, v in enumerate(row) if v]
            if len(cols) > 1:
                bs = cols[1] - cols[0]
                off = cols[0]
                break
    pts = [(r, c, v) for r, row in enumerate(g) for c, v in enumerate(row) if v and v != lc]
    if not pts:
        return [[0]*3 for _ in range(3)]
    blocks = [((r - off)//bs, (c - off)//bs, v) for r, c, v in pts]
    min_br = min(b[0] for b in blocks)
    min_bc = min(b[1] for b in blocks)

    def color_at(br, bc):
        r = br * bs + off
        c = bc * bs + off
        if 0 <= r < len(g) and 0 <= c < len(g[0]):
            return g[r][c]
        return 0

    out = [[0]*3 for _ in range(3)]
    for i in range(3):
        for j in range(3):
            cells = [
                color_at(min_br + i, min_bc + j),
                color_at(min_br + i, min_bc + j + 1),
                color_at(min_br + i + 1, min_bc + j),
                color_at(min_br + i + 1, min_bc + j + 1)
            ]
            if cells[0] and cells[0] != lc and all(c == cells[0] for c in cells):
                out[i][j] = cells[0]
    return out

